import { Component, Element, Event, EventEmitter, h, Listen, Prop, State, Watch } from '@stencil/core';
import isEqual from 'lodash.isequal';
import { TreeMenuItem } from '@src/mx-components/menu-item/mx-menu-item/menu-item.interface';
import { isNullOrUndefined } from '@src/utils/mx-utils/utils';
import { getOffset } from '@src/utils/mx-utils/domUtils';
import {
  findItemInArrayByUuid, mergeSelectedItems,
  removeChildInArrayByUuid,
  removeItemsWithEmptyChildrenInPlace,
  retrieveAllSelectedChildren,
  setParentStatus
} from '@src/mx-components/menu-item/mx-menu-item/menu-item-utils';
import itemUtils from '../../../utils/mx-utils/mx-menu-item.utils';
import { MxMenuItemCustomEvent } from '@src/components';
import 'stencil-virtual-scroll';

@Component({
  tag: 'mx-multi-select-list',
  styleUrl: 'mx-multi-select-list.css'
})
export class MxMultiSelectList {
  @Element() hostEl: HTMLMxMultiSelectListElement;

  /** Array of objects that has label, value and selected, for example: {label: 'Carrot', value: 'carror', selected: false}. */
  @Prop() readonly items: TreeMenuItem[] = [];

  /** Enables or disables the virtual scroll functionality to increase performance.
   * Enabling this may cause style issues when font sizes or zoom levels are changed from their defaults.
   * Disabled by default. */
  @Prop() readonly enableVirtualScroll: boolean = false;

  @Watch('items')
  onItemsChange() {
    this.setUp();
    this.getSpaceFromViewport();
    this.getViewPortHeight();
  }

  /** The item list that sets the default selections, should be subset of items. */
  @Prop() readonly selectedItems: TreeMenuItem[] = [];

  @Watch('selectedItems')
  handleSelectedItemsChange() {
    this.setUp();
  }

  /** Sets checkboxes to Compact KDS checkbox. */
  @Prop() readonly compactCheckbox: boolean = false;
  /** Emits event on when an item is selected. */
  @Event() itemSelected: EventEmitter;

  @State() selectAllItem: TreeMenuItem = {
    label: 'Select All',
    value: 'all',
    selected: false,
    disabled: false,
    indeterminate: false
  };

  @State() changedItems: TreeMenuItem[] = [];

  @State() itemWidth: number | null = null;

  @State() itemHeights: number[] = [];

  @Watch('changedItems')
  onChangedItemsChange(newValue: TreeMenuItem[]) {
    this.setSelectAllItem(newValue);
  }

  /** Emitted when the user clicks to close the menu item and hide child menu. */
  @Event() menuItemClosed: EventEmitter<TreeMenuItem>;
  /** Emitted when the user clicks to open the menu item and display child menu. */
  @Event() menuItemOpened: EventEmitter<TreeMenuItem>;

  @Listen('resize', { target: 'window' })
  handleResize() {
    this.itemWidth = this.hostEl.parentElement.clientWidth;
  }

  @Listen('menuItemOpened')
  @Listen('menuItemClosed')
  handleMenuItems() {
    this.itemHeights = this.enableVirtualScroll ? this.calculateItemHeights(this.changedItems) : this.itemHeights;
  }

  private spaceBelow = 500;
  private spaceAbove = 500;
  private listHeight = 0;

  componentWillLoad() {
    this.getSpaceFromViewport();
    this.getViewPortHeight();
    this.setUp();
    this.itemHeights = this.enableVirtualScroll && this.calculateItemHeights(this.changedItems);
  }

  private setUp() {
    const changedItems = this.items.map((item) => this.formatItem(item));
    this.setInitialState(changedItems, this.selectedItems);
    this.changedItems = [...changedItems];
  }

  private setSelectAllItem(changedItems = this.changedItems) {

    let selectedItemCount = 0;

    (function countChildren(items: any) {
      const realItems = items.children || items;
      if (realItems != null) {
        realItems.forEach((item) => {
          if (item.children != null) {
            countChildren(item);
          } else {
            selectedItemCount++;
          }
        });
      }
    })(changedItems);

    const tempArray = [];
    retrieveAllSelectedChildren(changedItems, tempArray);
    const selectedItems = tempArray.length;

    const indeterminate = selectedItems > 0 && selectedItems < selectedItemCount;
    const selected = !indeterminate && selectedItemCount === selectedItems;
    this.selectAllItem = { ...this.selectAllItem, indeterminate, selected };
  }

  private setInitialState(items: any, selectedItems: any) {
    if (isNullOrUndefined(items) || isNullOrUndefined(selectedItems) || selectedItems.length === 0) {
      return;
    }
    const total = items.length;
    const selected = selectedItems.length;
    this.selectAllItem.selected = total === selected;
    this.selectAllItem.indeterminate = selected > 0 && total > selected;
    items.forEach((item) => {
      if (isNullOrUndefined(selectedItems)) {
        this.setState(item, null);
      } else {
        const input: any = selectedItems.find((inputItem) => item.uuid === inputItem.uuid);
        this.setState(item, input);
      }
    });
  }

  private setState(item, selectedItem) {
    // Resets states before any logic is done .
    item.selected = false;
    item.indeterminate = false;
    // If the item has any children, we need to loop through all of them to set their status.
    if (item.children) {
      item.children.forEach((child) => {
        // If selectedItem is not valid or does not have any children, set selected child to null.
        // This is going to be used on the upcoming function recursion.
        const selectedChild = isNullOrUndefined(selectedItem) || isNullOrUndefined(selectedItem.children)
          ? null : selectedItem.children.find((inputItem) => {
            // Checks if the child's label is the same as the selected item's label.
            return isEqual(child.uuid, inputItem.uuid);
          });
        // Call this function recursively as long as we keep having children.
        this.setState(child, selectedChild);
      });
    }
    // This is when we'll use the recursion value from selectedChild above.
    if (!isNullOrUndefined(selectedItem)) {
      // Set the selected/indeterminate values accordingly.
      if (isEqual(this.formatItem(item), this.formatItem(selectedItem))) {
        item.selected = true;
        item.indeterminate = false;
      } else {
        item.indeterminate = true;
        item.selected = false;
      }
      if (item.disabled) {
        item.indeterminate = false;
        item.selected = false;
      }
    }
  }

  private formatSelectedItem(item) {
    const tempItem = {
      label: item.label,
      value: item.value,
      uuid: item.uuid,
      displayChildren: item.hasOwnProperty('displayChildren') ? item.displayChildren : true
    };

    if (item.children && item.children.length > 0) {
      const children = item.children
        .filter((child) => child.selected || child.indeterminate)
        .map((child) => this.formatSelectedItem(child));
      return {
        ...tempItem,
        children
      };
    }
    return tempItem;
  }

  private formatItem(item, disabled = false) {
    const it = {
      label: item.label,
      value: item.value,
      uuid: item.uuid,
      displayChildren: item.hasOwnProperty('displayChildren') ? item.displayChildren : true
    };

    if (item.disabled || disabled == true) {
      it['disabled'] = true;
    }
    if (item.children && item.children.length > 0) {
      const children = item.children.map((child) => this.formatItem(child, item.disabled));
      return {
        ...it,
        children
      };
    }
    return it;
  }

  private getSpaceFromViewport() {
    const elementOffset = getOffset(this.hostEl.parentElement.parentElement);
    this.spaceAbove = window.innerHeight - (elementOffset.bottom - elementOffset.top);
    this.spaceBelow = window.innerHeight - elementOffset.bottom;
  }

  private getViewPortHeight(): void {
    if (!isNullOrUndefined(this.changedItems)) {
      let height: number = itemUtils.calculateListHeight(this.changedItems, this.compactCheckbox ? 32 : 34);
      if (this.spaceBelow < height && height > this.spaceAbove) {
        height = this.spaceAbove - 80;
      }
      // We only want to update the list height if it is greater than the previous one.
      // This avoids us updating to a smaller height when there are no results. (Throwing the UI off).
      if (height > this.listHeight) {
        this.listHeight = height;
      }
    }
  }

  private createParents(parent: TreeMenuItem, formattedItem: TreeMenuItem) {
    if (!isNullOrUndefined(parent)) {
      const parentWithChild: any = this.formatSelectedItem(parent);
      parentWithChild.children = [formattedItem];
      if (!isNullOrUndefined(parent.parent)) {
        this.createParents(parent.parent, parentWithChild);
      } else {
        const findParentWithChild = findItemInArrayByUuid(this.selectedItems, parentWithChild.uuid);
        if (!isNullOrUndefined(findParentWithChild)) {
          findParentWithChild.children = [...findParentWithChild.children, ...parentWithChild.children];
        } else {
          // We're intentionally mutating here, so we don't render twice.
          this.selectedItems.push(parentWithChild);
        }
      }
    }
  }

  private readonly setSelectAllState = (event: CustomEvent<TreeMenuItem>) => {
    const selectedItem = event.detail;

    if (!isNullOrUndefined(selectedItem)) {
      const findItem = findItemInArrayByUuid(this.selectedItems, selectedItem.uuid);
      if (isNullOrUndefined(findItem)) {
        if (selectedItem.selected || selectedItem.indeterminate) {
          const formattedItem = this.formatSelectedItem(selectedItem);
          const itemParent = selectedItem.parent;
          if (isNullOrUndefined(itemParent)) {
            // We're intentionally mutating here, so we don't render twice.
            this.selectedItems.push(formattedItem);
          } else {
            const findParent = findItemInArrayByUuid(this.selectedItems, itemParent.uuid);
            // If we don't have a parent already on the list of selected items, we need to add the entire parent with the child selected.
            if (isNullOrUndefined(findParent)) {
              this.createParents(selectedItem.parent, formattedItem);
            } else {
              findParent.children = [...findParent.children, formattedItem];
            }
          }
        }
      } else {
        removeChildInArrayByUuid(this.selectedItems, findItem.uuid);
      }
      removeItemsWithEmptyChildrenInPlace(this.selectedItems);
    }

    // Let's force an update.
    this.changedItems = [...this.changedItems];
    this.itemSelected.emit(this.selectedItems);
  };

  private readonly toggleSelectAll = (event: MxMenuItemCustomEvent<TreeMenuItem>) => {
    const { selected } = event.detail;

    this.changedItems.forEach((item) => {
      if (!item.disabled) {
        item.selected = selected;
        item.indeterminate = false;
        this.setChildrenStatus(item.children, selected);
      }
    });

    const selectedItems = this.changedItems
      .filter((it) => it.selected || it.indeterminate)
      .map((it) => this.formatSelectedItem(it));

    // we need to keep previous selected items also
    this.itemSelected.emit(selectedItems.length === 0 ? [] : mergeSelectedItems(this.selectedItems, selectedItems));
  };


  private setChildrenStatus(children: any[], status) {
    if (isNullOrUndefined(children)) {
      return;
    }
    children
      .filter((child) => isNullOrUndefined(child.disabled) || !child.disabled)
      .forEach((child) => {
        child.selected = status;
        child.indeterminate = false;
        setParentStatus(child.parent);
        this.setChildrenStatus(child.children, status);
      });
  }

  private readonly renderItem = (item, index, isLast = false) => {
    return (
      <mx-menu-item
        class={'addable-menu-item' + (isLast ? ' last-item' : '')}
        key={index}
        item={item}
        isDisabled={item.disabled || false}
        showCheckbox={true}
        displayChildren={item.displayChildren}
        compactCheckbox={this.compactCheckbox}
        showTitle={true}
        onMenuItemSelected={this.setSelectAllState}></mx-menu-item>
    );
  };

  private readonly calculateChildrenHeight = (item, length) => {
    if (item.children && item.displayChildren) {
      length += item.children.length;
      item.children.forEach((child) => {
        length = this.calculateChildrenHeight(child, length);
      });
    }
    return length;
  }

  private readonly calculateItemHeights = (items) => {
    const estimatedItemHeight = 32;
    const itemHeights = [];
    items.forEach((item) => {
      let height = estimatedItemHeight;
      if (item.children) {
        height *= this.calculateChildrenHeight(item, 1);
      }
      itemHeights.push(height);
    });
    return itemHeights;
  }

  render() {
    const itemWidth = this.itemWidth || this.hostEl.parentElement.clientWidth;
    const estimatedItemHeight = this.compactCheckbox ? 32 : 34;

    return (
      <ul class='mx-select-list'>
        {
          this.items?.length === 0 && (<mx-menu-item
            class='no-results-addable'
            label='No Results Found'
            showCheckbox={false}
            isDisabled={false}
            compactCheckbox={this.compactCheckbox}></mx-menu-item>)
        }

        {
          this.items?.length > 0 && (<mx-menu-item
            class='select-all-addable'
            item={this.selectAllItem}
            showCheckbox={true}
            isDisabled={this.selectAllItem?.disabled}
            displayChildren={this.selectAllItem?.displayChildren ?? true}
            compactCheckbox={this.compactCheckbox}
            onMenuItemSelected={this.toggleSelectAll}></mx-menu-item>)
        }

        { this.items?.length > 0 && (<hr/>) }

        { !this.enableVirtualScroll ?
          (<div class='overflow-y-auto' style={{ height: this.listHeight + 'px' }}>
            {
              this.changedItems?.map((item, index) =>
                this.renderItem(item, index, index === this.changedItems.length - 1))
            }
          </div>) :
          (<virtual-scroll-list
            itemCount={this.changedItems.length}
            renderItem={(i) => this.renderItem(this.changedItems[i], i, i === this.changedItems.length - 1)}
            itemWidth={itemWidth}
            itemHeights={this.itemHeights}
            estimatedItemHeight={estimatedItemHeight}
            style={{
              display: 'flex',
              width: 'round(up, 100%, 1px)',
              height: this.listHeight + 'px',
              'overflow-x': 'hidden',
              'overflow-y': 'auto'
            }}
          />)
        }
      </ul>
    );
  }
}
